import java.io.BufferedWriter;
import java.io.FileWriter;
import org.owasp.esapi.ESAPI;

public class XSSFixedCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Assuming this method is called with user input
        processUserInput(userInput);
    }

    public static void processUserInput(String userInput) {
        try {
            BufferedWriter out = new BufferedWriter(new FileWriter("output.html"));
            out.write("<html><body>");
            out.write("<p>User input: " + ESAPI.encoder().encodeForHTML(userInput) + "</p>");
            out.write("</body></html>");
            out.close();
        } catch (IOException e) {
            System.out.println("Error writing output file");
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
